import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{o as e,c as n,e as s}from"./app-be253e4c.js";const c={},o=s(`<h1 id="ln命令" tabindex="-1"><a class="header-anchor" href="#ln命令" aria-hidden="true">#</a> ln命令</h1><p><code>ln</code>命令用来为文件创建链接，链接类型分为硬链接和软链接两种，软链接又称符号链接，默认的链接类型是硬链接，如果要创建符号链接必须使用<code>-s</code>选项，符号链接文件不是一个独立的文件，其很多属性依赖于源文件，所以给符号链接文件设置存取权限是没有意义的。</p><h2 id="语法" tabindex="-1"><a class="header-anchor" href="#语法" aria-hidden="true">#</a> 语法</h2><div class="language-bash" data-ext="sh"><pre class="language-bash"><code> <span class="token function">ln</span> <span class="token punctuation">[</span>-bdfinsvF<span class="token punctuation">]</span> <span class="token punctuation">[</span>-S backup-suffix<span class="token punctuation">]</span> <span class="token punctuation">[</span>-V <span class="token punctuation">{</span>numbered,existing,simple<span class="token punctuation">}</span><span class="token punctuation">]</span> <span class="token punctuation">[</span>--help<span class="token punctuation">]</span> <span class="token punctuation">[</span><span class="token punctuation">..</span>.<span class="token punctuation">]</span> <span class="token punctuation">[</span>origin<span class="token punctuation">]</span> <span class="token punctuation">[</span>target<span class="token punctuation">]</span>
</code></pre></div><h2 id="参数" tabindex="-1"><a class="header-anchor" href="#参数" aria-hidden="true">#</a> 参数</h2><ul><li><code>-b, --backup</code>: 删除，覆盖目标文件之前的备份。</li><li><code>-d, -F, --directory</code>: 建立目录的硬链接。</li><li><code>-f, --force</code>: 强行建立文件或目录的链接，不论文件或目录是否存在。</li><li><code>-i, --interactive</code>: 覆盖既有文件之前先询问用户。</li><li><code>-n, --no-dereference</code>: 把符号链接的目的目录视为一般文件。</li><li><code>-s, --symbolic</code>: 对源文件建立符号链接，而非硬链接。</li><li><code>-S &lt;backup-suffix&gt;, --suffix=&lt;backup-suffix&gt;</code>: 用<code>-b</code>参数备份目标文件后，备份文件的字尾会被加上一个备份字符串，预设的备份字符串是符号<code>~</code>，用户可通过<code>-S</code>参数来改变它。</li><li><code>-v, --verbose</code>: 显示指令执行过程。</li><li><code>-V &lt;backup method&gt;, --version-control=&lt;backup method&gt;</code>: 用<code>-b</code>参数备份目标文件后，备份文件的字尾会被加上一个备份字符串，这个字符串不仅可用<code>-S</code>参数变更，当使用<code>-V</code>参数&lt;备份方式&gt;指定不同备份方式时，也会产生不同字尾的备份字符串。</li><li><code>--help</code>: 在线帮助。</li><li><code>--version</code>: 显示版本信息。</li></ul><h2 id="链接方式" tabindex="-1"><a class="header-anchor" href="#链接方式" aria-hidden="true">#</a> 链接方式</h2><h3 id="软链接" tabindex="-1"><a class="header-anchor" href="#软链接" aria-hidden="true">#</a> 软链接</h3><ul><li>软链接以路径的形式存在，类似于<code>Windows</code>操作系统中的快捷方式。</li><li>软链接可以 跨文件系统，硬链接不可以。</li><li>软链接可以对一个不存在的文件名进行链接。</li><li>软链接可以对目录进行链接。</li></ul><h3 id="硬链接" tabindex="-1"><a class="header-anchor" href="#硬链接" aria-hidden="true">#</a> 硬链接</h3><ul><li>硬链接，以文件副本的形式存在，但不占用实际空间。</li><li>不允许给目录创建硬链接。</li><li>硬链接只有在同一个文件系统中才能创建。</li></ul><h2 id="示例" tabindex="-1"><a class="header-anchor" href="#示例" aria-hidden="true">#</a> 示例</h2><p>为<code>file.txt</code>创建软链接<code>filesoftlink</code>。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">ln</span> <span class="token parameter variable">-s</span> file.txt filesoftlink
</code></pre></div><p>为<code>file.txt</code>创建硬链接<code>filehardlink</code>。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">ln</span> file.txt filehardlink
</code></pre></div><p>显示版本信息。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">ln</span> <span class="token parameter variable">--version</span>
</code></pre></div>`,18),i=[o];function t(l,d){return e(),n("div",null,i)}const u=a(c,[["render",t],["__file","ln.html.vue"]]);export{u as default};
